+import jdk.test.lib.net.SimpleSSLContext;
+import jdk.test.lib.net.URIBuilder;
+import org.junit.jupiter.api.BeforeAll;
+import org.junit.jupiter.api.function.ThrowingConsumer;
+import org.junit.jupiter.params.ParameterizedTest;
+import org.junit.jupiter.params.provider.ValueSource;
+
+import javax.net.ssl.HttpsURLConnection;
+import javax.net.ssl.SSLContext;
+import java.io.BufferedReader;
+import java.io.BufferedWriter;
+import java.io.IOException;
+import java.io.InputStreamReader;
+import java.io.OutputStreamWriter;
+import java.net.HttpURLConnection;
+import java.net.InetAddress;
+import java.net.Proxy;
+import java.net.ServerSocket;
+import java.time.Duration;
+import java.util.ArrayList;
+import java.util.List;
+import java.util.concurrent.CompletableFuture;
+import java.util.concurrent.Future;
+import java.util.concurrent.TimeUnit;
+import java.util.concurrent.atomic.AtomicBoolean;
+import java.util.concurrent.locks.LockSupport;
+import java.util.logging.ConsoleHandler;
+import java.util.logging.Level;
+import java.util.logging.Logger;
+
+import static java.nio.charset.StandardCharsets.US_ASCII;
+import static jdk.test.lib.Utils.adjustTimeout;
+import static org.junit.jupiter.api.Assertions.assertEquals;
+import static org.junit.jupiter.api.Assertions.assertFalse;
+import static org.junit.jupiter.api.Assertions.assertNull;
+import static org.junit.jupiter.api.Assertions.assertTrue;
+
+/*
+ * @test
+ * @bug 8009650 8180483
+ * @summary Verifies the cached keep-alive connection reuse in combination
+ *          with "streaming POST" requests.
+ *
+ *          A "streaming POST" is controlled by `HttpURLConnection::streaming`,
+ *          which becomes `true` when the caller uses either
+ *          `setFixedLengthStreamingMode()` or `setChunkedStreamingMode()`, and
+ *          *then writes the request body*. Non-streaming mode uses
+ *          `PosterOutputStream.java`, which buffers the body and makes replay
+ *          possible. Whereas, streaming mode allows user to directly write to
+ *          the socket, so the body is not safely replayable. For many ordinary
+ *          (i.e., non-streaming) requests, if a connection reuse fails, the
+ *          stack can often recover by opening a new connection and retrying;
+ *          see retry logic in `HttpClient`. OTOH, for a "streaming POST", retry
+ *          is dangerous or impossible because the body may already be in
+ *          flight and is not buffered for replay. Hence,
+ *          `HttpClient::available` tries to check whether the cached socket is
+ *          still usable by doing a 1ms `read()`. Though that probe is
+ *          destructive: it can consume and strand one byte from the socket
+ *          input stream. Hence, probe failures should result in removal of the
+ *          connection. And that is what we strive to verify here.
+ *
+ * @modules java.base/sun.net
+ *          java.base/sun.net.www.http:+open
+ * @library /test/lib
+ *
+ * @comment `othervm` is required since the `HttpURLConnection` logger state is tainted.
+ * @run junit/othervm ${test.main.class}
+ */
+
+class StreamingPostHttpClientReuseTest {
+
+    private static final java.nio.charset.Charset CHARSET = US_ASCII;
+
+    private static final String REQUEST_BODY = "History has failed us, but no matter."
+            // Appending CRLF to play nicely with `BufferedReader`
+            + "\r\n";
+
+    /// A (maximum) chunk length big enough to fit the expected request
+    /// body into a single chunk.
+    ///
+    /// This will help with, for the request body, say, `foo bar`, transmitting
+    ///
+    ///     7          # Chunk length (hex)
+    ///     foo bar    # Chunk payload
+    ///
+    /// instead of, for instance,
+    ///
+    ///     2          # Chunk length (hex)
+    ///     fo         # Chunk payload
+    ///     5          # Chunk length (hex)
+    ///     o bar      # Chunk payload
+    ///
+    /// This allows us to simply derive [CHUNKED_REQUEST_BODY_LINES] from
+    /// [REQUEST_BODY] without resorting to any complicated re-assembly of
+    /// chunks.
+    private static final int CHUNK_LENGTH = REQUEST_BODY.length() + 1024;
+
+    /// Chunked request body encoding of [REQUEST_BODY].
+    private static final List<String> CHUNKED_REQUEST_BODY_LINES = List.of(
+            "%x".formatted(REQUEST_BODY.length()),
+            REQUEST_BODY.trim());
+
+    private static final Logger LOGGER =
+            Logger.getLogger(StreamingPostHttpClientReuseTest.class.getCanonicalName());
+
+    // Class-level anchor to avoid the `HttpURLConnection` logger getting GC'ed
+    private static final Logger HUC_LOGGER =
+            Logger.getLogger("sun.net.www.protocol.http.HttpURLConnection");
+
+    private static final SSLContext SSL_CONTEXT = SimpleSSLContext.findSSLContext();
+
+    private static final InetAddress LOOPBACK_ADDRESS = InetAddress.getLoopbackAddress();
+
+    static {
+        HttpsURLConnection.setDefaultSSLSocketFactory(SSL_CONTEXT.getSocketFactory());
+        HttpsURLConnection.setDefaultHostnameVerifier((_, _) -> true);
+    }
+
+    @BeforeAll
+    static void init() {
+        increaseLoggerVerbosity(HUC_LOGGER);
+    }
+
+    private static void increaseLoggerVerbosity(Logger logger) {
+        logger.setLevel(Level.FINEST);
+        var handler = new ConsoleHandler();
+        handler.setLevel(Level.FINEST);
+        logger.addHandler(handler);
+    }
+
+    @ParameterizedTest
+    @ValueSource(booleans = {false, true})
+    void testChunkedRequestCanReuseConnection(boolean secure) throws Throwable {
+        testStreamingPostRequestCanReuseConnection(
+                secure,
+                StreamingPostHttpClientReuseTest::configureChunkedRequest,
+                StreamingPostHttpClientReuseTest::verifyChunkedRequest);
+    }
+
+    private static void configureChunkedRequest(HttpURLConnection connection) throws Exception {
+        connection.setRequestMethod("POST");
+        connection.setChunkedStreamingMode(CHUNK_LENGTH);
+        connection.setDoOutput(true);
+    }
+
+    private static void verifyChunkedRequest(
+            BufferedReader clientInputReader,
+            List<String> lines)
+            throws Exception {
+        verifyRequestTransferEncodingHeader(lines);
+        lines = readRequestLines(clientInputReader);
+        assertEquals(CHUNKED_REQUEST_BODY_LINES, lines);
+    }
+
+    @ParameterizedTest
+    @ValueSource(booleans = {false, true})
+    void testFixedLengthRequestCanReuseConnection(boolean secure) throws Throwable {
+        testStreamingPostRequestCanReuseConnection(
+                secure,
+                StreamingPostHttpClientReuseTest::configureFixedLengthRequest,
+                StreamingPostHttpClientReuseTest::verifyFixedLengthRequest);
+    }
+
+    private static void configureFixedLengthRequest(HttpURLConnection connection) throws Exception {
+        connection.setRequestMethod("POST");
+        connection.setFixedLengthStreamingMode(REQUEST_BODY.length());
+        connection.setDoOutput(true);
+    }
+
+    private static void verifyFixedLengthRequest(
+            BufferedReader clientInputReader,
+            List<String> lines)
+            throws Exception {
+        verifyRequestContentLengthHeader(lines, REQUEST_BODY.length());
+        assertEquals(REQUEST_BODY, clientInputReader.readLine() + "\r\n");
+    }
+
+    /// Verifies that a "streaming POST" can reuse an existing established connection.
+    private static void testStreamingPostRequestCanReuseConnection(
+            boolean secure,
+            ThrowingConsumer<HttpURLConnection> preConnectConsumer,
+            ThrowingBiConsumer<BufferedReader, List<String>> requestVerifier)
+            throws Throwable {
+        try (var serverSocket = createServerSocket(secure)) {
+
+            // Issue the initial HEAD request to admit a connection to the cache
+            var responseCodeFuture = executeRequest(
+                    secure,
+                    serverSocket,
+                    connection -> connection.setRequestMethod("HEAD"),
+                    _ -> {});
+
+            // Accept the initial HEAD request
+            try (var clientSocket = serverSocket.accept();
+                 var clientOutputWriter = new BufferedWriter(
+                         new OutputStreamWriter(clientSocket.getOutputStream(), CHARSET));
+                 var clientInputReader = new BufferedReader(
+                         new InputStreamReader(clientSocket.getInputStream(), CHARSET))) {
+
+                verifyInitialHeadRequest(
+                        clientInputReader, clientOutputWriter, responseCodeFuture);
+
+                // -------------------------------------------------------------
+                // At this stage the connection is assumed to be admitted into
+                // the keep-alive cache. Consequently, it should be reused for
+                // the following "streaming POST".
+                // -------------------------------------------------------------
+
+                // Issue a "streaming POST" request
+                responseCodeFuture = executeRequest(
+                        secure,
+                        serverSocket,
+                        preConnectConsumer,
+                        connection -> {
+                            try (var requestOutputStream = connection.getOutputStream()) {
+                                requestOutputStream.write(REQUEST_BODY.getBytes(CHARSET));
+                            }
+                        });
+
+                // Verify the "streaming POST" request
+                LOGGER.info("Verifying the request...");
+                var lines = readRequestLines(clientInputReader);
+                verifyRequestMethod(lines, "POST");
+                verifyRequestConnectionKeepAliveHeader(lines);
+                requestVerifier.accept(clientInputReader, lines);
+
+                // Respond to the "streaming POST" request
+                LOGGER.info("Responding to the request...");
+                clientOutputWriter.write("HTTP/1.1 204 OK\r\n\r\n");
+                clientOutputWriter.flush();
+
+                // Verify the "streaming POST" request response
+                LOGGER.info("Obtaining the response status code...");
+                assertEquals(204, responseCodeFuture.get());
+
+                // -------------------------------------------------------------
+                // At this stage we've proved that the connection is reused for
+                // the above "streaming POST". We know this, because we were
+                // able to serve the "streaming POST" request from the very same
+                // connection we've served the earlier HEAD.
+                // -------------------------------------------------------------
+
+            }
+        }
+    }
+
+    @ParameterizedTest
+    @ValueSource(booleans = {false, true})
+    void testChunkedRequestCanNotReuseConnDueToDirtySocket(boolean secure) throws Throwable {
+        testStreamingPostRequestCanNotReuseConnDueToDirtySocket(
+                secure,
+                StreamingPostHttpClientReuseTest::configureChunkedRequest,
+                StreamingPostHttpClientReuseTest::verifyChunkedRequest);
+    }
+
+    @ParameterizedTest
+    @ValueSource(booleans = {false, true})
+    void testFixedLengthRequestCanNotReuseConnDueToDirtySocket(boolean secure) throws Throwable {
+        testStreamingPostRequestCanNotReuseConnDueToDirtySocket(
+                secure,
+                StreamingPostHttpClientReuseTest::configureFixedLengthRequest,
+                StreamingPostHttpClientReuseTest::verifyFixedLengthRequest);
+    }
+
+    /// Verifies that a "streaming POST" fails to reuse an existing established
+    /// connection, because stale data is found on the socket.
+    private static void testStreamingPostRequestCanNotReuseConnDueToDirtySocket(
+            boolean secure,
+            ThrowingConsumer<HttpURLConnection> preConnectConsumer,
+            ThrowingBiConsumer<BufferedReader, List<String>> requestVerifier)
+            throws Throwable {
+        try (var serverSocket = createServerSocket(secure)) {
+
+            // Issue the initial HEAD request to admit a connection to the cache
+            var responseCodeFuture = executeRequest(
+                    secure,
+                    serverSocket,
+                    connection -> connection.setRequestMethod("HEAD"),
+                    _ -> {});
+
+            // Accept the initial HEAD request
+            try (var clientSocket = serverSocket.accept();
+                 var clientOutputWriter = new BufferedWriter(
+                         new OutputStreamWriter(clientSocket.getOutputStream(), CHARSET));
+                 var clientInputReader = new BufferedReader(
+                         new InputStreamReader(clientSocket.getInputStream(), CHARSET))) {
+
+                verifyInitialHeadRequest(
+                        clientInputReader, clientOutputWriter, responseCodeFuture);
+
+                // -------------------------------------------------------------
+                // At this stage the connection is assumed to be admitted into
+                // the keep-alive cache. A consequent "streaming POST" should be
+                // able to reuse it, as tested in
+                // `testStreamingPostRequestCanReuseConnection()`. Here we will
+                // intentionally write (unexpected) data to the socket. Then we
+                // will verify that "streaming POST", upon detecting the stale
+                // data,
+                //
+                // 1. Closes the socket
+                // 2. Creates a new connection
+                // -------------------------------------------------------------
+
+                // Write (unexpected) data to the socket
+                LOGGER.info("Tainting the socket...");
+                clientOutputWriter.write("unexpected data");
+                clientOutputWriter.flush();
+
+                // There is a race condition we need to deal with. When we taint
+                // the socket by writing data to it, it might not be instantly
+                // visible to the `HttpClient::available`, which invokes a
+                // socket `read()` using 1ms timeout. Hence, we give the
+                // transfer some time for the data to get delivered.
+                Thread.sleep(adjustTimeout(500));
+
+                // Issue a "streaming POST" request
+                responseCodeFuture = executeRequest(
+                        secure,
+                        serverSocket,
+                        preConnectConsumer,
+                        connection -> {
+                            try (var requestOutputStream = connection.getOutputStream()) {
+                                requestOutputStream.write(REQUEST_BODY.getBytes(CHARSET));
+                            }
+                        });
+
+                // Verify the connection is closed
+                verifySocketClosed(clientInputReader);
+
+                // -------------------------------------------------------------
+                // At this stage we've proved that the connection is *NOT*
+                // reused for the above "streaming POST". Otherwise, we would
+                // have read a valid request line above.
+                // -------------------------------------------------------------
+
+            }
+
+            // Accept the "streaming POST" request
+            try (var clientSocket = serverSocket.accept();
+                 var clientOutputWriter = new BufferedWriter(
+                         new OutputStreamWriter(clientSocket.getOutputStream(), CHARSET));
+                 var clientInputReader = new BufferedReader(
+                         new InputStreamReader(clientSocket.getInputStream(), CHARSET))) {
+
+                // Verify the "streaming POST" request
+                LOGGER.info("Verifying the request...");
+                var lines = readRequestLines(clientInputReader);
+                verifyRequestMethod(lines, "POST");
+                verifyRequestConnectionKeepAliveHeader(lines);
+                requestVerifier.accept(clientInputReader, lines);
+
+                // Respond to the "streaming POST" request
+                LOGGER.info("Responding to the request...");
+                clientOutputWriter.write("HTTP/1.1 204 OK\r\n\r\n");
+                clientOutputWriter.flush();
+
+                // Verify the "streaming POST" request response
+                LOGGER.info("Obtaining the response status code...");
+                assertEquals(204, responseCodeFuture.get());
+
+                // -------------------------------------------------------------
+                // At this stage we've proved that the "streaming POST" is
+                // served from a connection different from the one the initial
+                // HEAD request established.
+                // -------------------------------------------------------------
+
+            }
+        }
+    }
+
+    private static void verifySocketClosed(BufferedReader clientInputReader) throws Exception {
+        LOGGER.info("Verifying that the socket is closed...");
+        var readLineFuture = new CompletableFuture<String>();
+        var stopFlag = new AtomicBoolean(false);
+        var thread = Thread.ofVirtual()
+                .uncaughtExceptionHandler((_, e) -> readLineFuture.completeExceptionally(e))
+                .start(() -> {
+                    while (!stopFlag.get()) {
+                        try {
+                            var readLine = clientInputReader.readLine();
+                            readLineFuture.complete(readLine);
+                        } catch (IOException _) {
+                            readLineFuture.complete(null);
+                        }
+                        LockSupport.parkNanos(Duration.ofMillis(100).toNanos());
+                    }
+                });
+        try {
+            var readLine = readLineFuture.get(adjustTimeout(5), TimeUnit.SECONDS);
+            assertNull(readLine, "Unexpected line read!");
+        } finally {
+            stopFlag.set(true);
+            thread.interrupt();
+        }
+    }
+
+    @FunctionalInterface
+    private interface ThrowingBiConsumer<A, B> {
+
+        void accept(A a, B b) throws Exception;
+
+    }
+
+    private static ServerSocket createServerSocket(boolean secure) throws Exception {
+        return secure
+                ? SSL_CONTEXT.getServerSocketFactory().createServerSocket(0, 0, LOOPBACK_ADDRESS)
+                : new ServerSocket(0, 0, LOOPBACK_ADDRESS);
+    }
+
+    private static void verifyInitialHeadRequest(
+            BufferedReader clientInputReader,
+            BufferedWriter clientOutputWriter,
+            Future<Integer> responseCodeFuture)
+            throws Exception {
+
+        // Special care needs to be taken in this initial request. Because we
+        // expect this connection to be admitted to the keep-alive cache.
+        // Judging from `sun.net.www.http.HttpClient`, a connection is kept
+        // alive only when the response body boundary is known. That is, one of
+        // the following must hold:
+        //
+        //  - Response contains a `Content-Length` header
+        //  - Response contains a `Transfer-Encoding: chunked` header
+        //  - A no-body status/method is used (i.e., HEAD, 204, 304)
+
+        // Verify the request
+        LOGGER.info("Verifying the request...");
+        var lines = readRequestLines(clientInputReader);
+        verifyRequestMethod(lines, "HEAD");
+        verifyRequestConnectionKeepAliveHeader(lines);
+
+        // Respond to the HEAD request
+        LOGGER.info("Responding to the request...");
+        clientOutputWriter.write("HTTP/1.1 204 OK\r\n\r\n");
+        clientOutputWriter.flush();
+
+        // Verify the request response
+        LOGGER.info("Obtaining the response status code...");
+        assertEquals(204, responseCodeFuture.get());
+
+    }
+
+    private static Future<Integer> executeRequest(
+            boolean secure,
+            ServerSocket serverSocket,
+            ThrowingConsumer<HttpURLConnection> preConnectConsumer,
+            ThrowingConsumer<HttpURLConnection> postConnectConsumer) {
+        LOGGER.info("Sending a request to " + serverSocket.getLocalSocketAddress() + "...");
+        CompletableFuture<Integer> responseCodeFuture = new CompletableFuture<>();
+        Thread.ofVirtual().name("executeRequest").start(() -> {
+            try {
+
+                // Create an (un-established!) `HttpURLConnection`
+                var connection = (HttpURLConnection) URIBuilder.newBuilder()
+                        .scheme(secure ? "https" : "http")
+                        .loopback()
+                        .port(serverSocket.getLocalPort())
+                        .toURL()
+                        .openConnection(Proxy.NO_PROXY);
+                connection.setConnectTimeout(10_000);
+                connection.setReadTimeout(10_000);
+                preConnectConsumer.accept(connection);
+
+                // Execute the request
+                connection.connect();
+                postConnectConsumer.accept(connection);
+                responseCodeFuture.complete(connection.getResponseCode());
+
+            } catch (Throwable t) {
+                responseCodeFuture.completeExceptionally(t);
+            }
+        });
+        return responseCodeFuture;
+    }
+
+    private static List<String> readRequestLines(BufferedReader requestStreamReader) throws IOException {
+        var lines = new ArrayList<String>();
+        for (String line; (line = requestStreamReader.readLine()) != null;) {
+            if (line.isEmpty()) {
+                break;
+            }
+            lines.add(line);
+            LOGGER.info("Read header line: " + line);
+        }
+        return lines;
+    }
+
+    private static void verifyRequestMethod(List<String> lines, String method) {
+        assertFalse(lines.isEmpty());
+        var line0 = lines.getFirst();
+        assertTrue(
+                line0.startsWith(method),
+                "Unexpected first request line: \"%s\"".formatted(line0));
+    }
+
+    private static void verifyRequestConnectionKeepAliveHeader(List<String> lines) {
+        verifyRequestHeader(lines, "Connection: keep-alive");
+    }
+
+    private static void verifyRequestContentLengthHeader(List<String> lines, int contentLength) {
+        verifyRequestHeader(lines, "Content-Length: " + contentLength);
+    }
+
+    private static void verifyRequestTransferEncodingHeader(List<String> lines) {
+        verifyRequestHeader(lines, "Transfer-Encoding: chunked");
+    }
+
+    private static void verifyRequestHeader(List<String> lines, String header) {
+        assertTrue(
+                lines.stream().anyMatch(line -> line.equalsIgnoreCase(header)),
+                "Couldn't find a \"%s\" header!".formatted(header));
+    }
+
+}
